  ('behovsanalys', 'Hur stor andel öppna frågor bör du ställa i behovsanalysen?', 'What share of open questions should you ask in the needs analysis?', '¿Qué proporción de preguntas abiertas deberías hacer?', $j$["Cirka 20 %", "Cirka 50 %", "Cirka 80 %"]$j$::jsonb, $j$["About 20%", "About 50%", "About 80%"]$j$::jsonb, $j$["Un 20%", "Un 50%", "Un 80%"]$j$::jsonb, 2, 'Tumregeln är ca 80 % öppna frågor.', 'Rule of thumb is about 80% open questions.', 'La regla general es alrededor del 80%.', 1),
  ('behovsanalys', 'Vilken fråga är öppen?', 'Which question is open?', '¿Qué pregunta es abierta?', $j$["Är ni nöjda med er hemsida?", "Hur får ni in nya kunder idag?", "Har ni en budget?"]$j$::jsonb, $j$["Are you happy with your website?", "How do you get new customers today?", "Do you have a budget?"]$j$::jsonb, $j$["¿Estáis contentos con vuestra web?", "¿Cómo conseguís clientes hoy?", "¿Tenéis presupuesto?"]$j$::jsonb, 1, 'Öppna frågor får kunden att prata.', 'Open questions get the customer talking.', 'Las preguntas abiertas hacen hablar al cliente.', 2),
