  ('behovsanalys', 'Hur mycket bör du lyssna jämfört med att prata?', 'How much should you listen versus talk?', '¿Cuánto deberías escuchar frente a hablar?', $j$["Prata mest", "Ungefär lika", "Lyssna mest"]$j$::jsonb, $j$["Talk most", "About equal", "Listen most"]$j$::jsonb, $j$["Hablar más", "Más o menos igual", "Escuchar más"]$j$::jsonb, 2, 'Lyssna mer än du pratar – ca 70 %.', 'Listen more than you talk – about 70%.', 'Escucha más de lo que hablas, ~70%.', 4),
  ('behovsanalys', 'Vad börjar en öppen fråga ofta med?', 'What does an open question often start with?', '¿Con qué empieza a menudo una pregunta abierta?', $j$["Är/Har/Vill", "Hur/Vad/Varför", "Ja/Nej"]$j$::jsonb, $j$["Are/Have/Do", "How/What/Why", "Yes/No"]$j$::jsonb, $j$["¿Es/Tenéis/Queréis?", "Cómo/Qué/Por qué", "Sí/No"]$j$::jsonb, 1, 'Öppna frågor börjar med Hur, Vad, Varför.', 'Open questions start with How, What, Why.', 'Empiezan con Cómo, Qué, Por qué.', 5),
