  ('behovsanalys', 'När använder du helst slutna frågor?', 'When do you preferably use closed questions?', '¿Cuándo usar preferiblemente preguntas cerradas?', $j$["I början", "För att bekräfta och stänga", "Aldrig"]$j$::jsonb, $j$["At the start", "To confirm and close", "Never"]$j$::jsonb, $j$["Al principio", "Para confirmar y cerrar", "Nunca"]$j$::jsonb, 1, 'Spara slutna till att bekräfta och stänga.', 'Save closed ones to confirm and close.', 'Resérvalas para confirmar y cerrar.', 7),
  ('behovsanalys', 'Vad menas med att ''hitta smärtan''?', 'What does ''find the pain'' mean?', '¿Qué significa ''encontrar el dolor''?', $j$["Sänka priset", "Gräva tills du hittar det verkliga behovet", "Avsluta snabbt"]$j$::jsonb, $j$["Lower the price", "Dig until you find the real need", "Close quickly"]$j$::jsonb, $j$["Bajar el precio", "Indagar hasta la necesidad real", "Cerrar rápido"]$j$::jsonb, 1, 'Gräv tills du hittar det verkliga behovet.', 'Dig until you find the real need.', 'Indaga hasta encontrar la necesidad real.', 8),
